9	import io.github.hectorvent.floci.services.cognito.model.CognitoGroup;
10	import io.github.hectorvent.floci.services.cognito.model.CognitoUser;
11	import io.github.hectorvent.floci.services.cognito.model.ResourceServer;
12	import io.github.hectorvent.floci.services.cognito.model.ResourceServerScope;
13	import io.github.hectorvent.floci.services.cognito.model.UserPool;
14	import io.github.hectorvent.floci.services.cognito.model.UserPoolClient;
15	import jakarta.enterprise.context.ApplicationScoped;
16	import jakarta.inject.Inject;
17	import org.jboss.logging.Logger;
18	
19	import java.nio.charset.StandardCharsets;
20	import java.security.KeyFactory;
21	import java.security.KeyPair;
22	import java.security.KeyPairGenerator;
23	import java.security.MessageDigest;
24	import java.security.PrivateKey;
25	import java.security.PublicKey;
26	import java.security.Signature;
27	import java.security.interfaces.RSAPublicKey;
28	import java.security.spec.PKCS8EncodedKeySpec;
29	import java.security.spec.X509EncodedKeySpec;
30	import java.util.*;
31	import java.util.concurrent.ConcurrentHashMap;
32	import java.util.stream.Collectors;
33	
34	@ApplicationScoped
35	public class CognitoService {
36	
37	    private static final Logger LOG = Logger.getLogger(CognitoService.class);
38	
39	    private final StorageBackend<String, UserPool> poolStore;
40	    private final StorageBackend<String, UserPoolClient> clientStore;
41	    private final StorageBackend<String, ResourceServer> resourceServerStore;
42	    private final StorageBackend<String, CognitoUser> userStore;
43	    private final StorageBackend<String, CognitoGroup> groupStore;
44	    private final String baseUrl;
45	    private final RegionResolver regionResolver;
46	
47	    // Keyed by session token; contains SRP ephemeral state (bPrivate, B, A, secretBlock)
48	    private final ConcurrentHashMap<String, SrpSession> srpSessions = new ConcurrentHashMap<>();
49	
50	    private record SrpSession(String userPoolId, String username, String clientId,
51	                               String aHex, String bHex, String bPublicHex,
52	                               String secretBlockBase64) {}
53	
54	    @Inject
55	    public CognitoService(StorageFactory storageFactory, EmulatorConfig emulatorConfig, RegionResolver regionResolver) {
56	        this.poolStore = storageFactory.create("cognito", "cognito-pools.json",
57	                new TypeReference<Map<String, UserPool>>() {});
58	        this.clientStore = storageFactory.create("cognito", "cognito-clients.json",
59	                new TypeReference<Map<String, UserPoolClient>>() {});
60	        this.resourceServerStore = storageFactory.create("cognito", "cognito-resource-servers.json",
61	                new TypeReference<Map<String, ResourceServer>>() {});
62	        this.userStore = storageFactory.create("cognito", "cognito-users.json",
63	                new TypeReference<Map<String, CognitoUser>>() {});
64	        this.groupStore = storageFactory.create("cognito", "cognito-groups.json",
65	                new TypeReference<Map<String, CognitoGroup>>() {});
66	        this.baseUrl = trimTrailingSlash(emulatorConfig.baseUrl());
67	        this.regionResolver = regionResolver;
68	    }
69	
70	    CognitoService(StorageBackend<String, UserPool> poolStore,
71	                   StorageBackend<String, UserPoolClient> clientStore,
72	                   StorageBackend<String, ResourceServer> resourceServerStore,
73	                   StorageBackend<String, CognitoUser> userStore,
74	                   StorageBackend<String, CognitoGroup> groupStore,
75	                   String baseUrl,
76	                   RegionResolver regionResolver) {
77	        this.poolStore = poolStore;
78	        this.clientStore = clientStore;
79	        this.resourceServerStore = resourceServerStore;
80	        this.userStore = userStore;
81	        this.groupStore = groupStore;
82	        this.baseUrl = baseUrl;
83	        this.regionResolver = regionResolver;
84	    }
85	
86	    // ──────────────────────────── User Pools ────────────────────────────
87	
88	    @SuppressWarnings("unchecked")
89	    public UserPool createUserPool(Map<String, Object> request, String region) {
90	        String name = (String) request.get("PoolName");
91	        String id = region + "_" + UUID.randomUUID().toString().replace("-", "").substring(0, 9);
92	        UserPool pool = new UserPool();
93	        pool.setId(id);
94	        pool.setName(name);
95	        pool.setArn(regionResolver.buildArn("cognito-idp", region, "userpool/" + id));
96	
97	        populateUserPool(pool, request);
98	
99	        ensureJwtSigningKeys(pool);
100	        poolStore.put(id, pool);
101	        LOG.infov("Created User Pool: {0}", id);
102	        return pool;
103	    }
104	
105	    public UserPool updateUserPool(Map<String, Object> request, String region) {
106	        String id = (String) request.get("UserPoolId");
107	        UserPool pool = describeUserPool(id);
108	
109	        populateUserPool(pool, request);
110	
111	        pool.setLastModifiedDate(System.currentTimeMillis() / 1000L);
112	        poolStore.put(id, pool);
113	        LOG.infov("Updated User Pool: {0}", id);
114	        return pool;
115	    }
116	
117	    @SuppressWarnings("unchecked")
118	    private void populateUserPool(UserPool pool, Map<String, Object> request) {
119	        if (request.containsKey("Policies")) pool.setPolicies((Map<String, Object>) request.get("Policies"));
120	        if (request.containsKey("DeletionProtection")) pool.setDeletionProtection((String) request.get("DeletionProtection"));
121	        if (request.containsKey("LambdaConfig")) pool.setLambdaConfig((Map<String, Object>) request.get("LambdaConfig"));
122	        if (request.containsKey("Schema")) pool.setSchemaAttributes((List<Map<String, Object>>) request.get("Schema"));
123	        if (request.containsKey("AutoVerifiedAttributes")) pool.setAutoVerifiedAttributes((List<String>) request.get("AutoVerifiedAttributes"));
124	        if (request.containsKey("AliasAttributes")) pool.setAliasAttributes((List<String>) request.get("AliasAttributes"));
125	        if (request.containsKey("UsernameAttributes")) pool.setUsernameAttributes((List<String>) request.get("UsernameAttributes"));
126	        if (request.containsKey("SmsVerificationMessage")) pool.setSmsVerificationMessage((String) request.get("SmsVerificationMessage"));
127	        if (request.containsKey("EmailVerificationMessage")) pool.setEmailVerificationMessage((String) request.get("EmailVerificationMessage"));
128	        if (request.containsKey("EmailVerificationSubject")) pool.setEmailVerificationSubject((String) request.get("EmailVerificationSubject"));
129	        if (request.containsKey("VerificationMessageTemplate")) pool.setVerificationMessageTemplate((Map<String, Object>) request.get("VerificationMessageTemplate"));
130	        if (request.containsKey("SmsAuthenticationMessage")) pool.setSmsAuthenticationMessage((String) request.get("SmsAuthenticationMessage"));
131	        if (request.containsKey("MfaConfiguration")) pool.setMfaConfiguration((String) request.get("MfaConfiguration"));
132	        if (request.containsKey("DeviceConfiguration")) pool.setDeviceConfiguration((Map<String, Object>) request.get("DeviceConfiguration"));
133	        if (request.containsKey("EmailConfiguration")) pool.setEmailConfiguration((Map<String, Object>) request.get("EmailConfiguration"));
134	        if (request.containsKey("SmsConfiguration")) pool.setSmsConfiguration((Map<String, Object>) request.get("SmsConfiguration"));
135	        if (request.containsKey("UserPoolTags")) pool.setUserPoolTags((Map<String, String>) request.get("UserPoolTags"));
136	        if (request.containsKey("AdminCreateUserConfig")) pool.setAdminCreateUserConfig((Map<String, Object>) request.get("AdminCreateUserConfig"));
137	        if (request.containsKey("UserPoolAddOns")) pool.setUserPoolAddOns((Map<String, Object>) request.get("UserPoolAddOns"));
138	        if (request.containsKey("UsernameConfiguration")) pool.setUsernameConfiguration((Map<String, Object>) request.get("UsernameConfiguration"));
139	        if (request.containsKey("AccountRecoverySetting")) pool.setAccountRecoverySetting((Map<String, Object>) request.get("AccountRecoverySetting"));
140	        if (request.containsKey("UserPoolTier")) pool.setUserPoolTier((String) request.get("UserPoolTier"));
141	    }
142	
143	    public UserPool describeUserPool(String id) {
144	        UserPool pool = poolStore.get(id)
145	                .orElseThrow(() -> new AwsException("ResourceNotFoundException", "User pool not found", 404));
146	        if (ensureJwtSigningKeys(pool)) {
147	            poolStore.put(id, pool);
148	        }
149	        return pool;
150	    }
151	
152	    public List<UserPool> listUserPools() {
153	        return poolStore.scan(k -> true);
154	    }
155	
156	    public void deleteUserPool(String id) {
157	        String prefix = id + "::";
158	        groupStore.scan(k -> k.startsWith(prefix))
159	                .forEach(g -> groupStore.delete(groupKey(id, g.getGroupName())));
160	        poolStore.delete(id);
161	    }
162	
163	    // ──────────────────────────── User Pool Clients ────────────────────────────
164	
165	    public UserPoolClient createUserPoolClient(String userPoolId, String clientName, boolean generateSecret,
166	                                               boolean allowedOAuthFlowsUserPoolClient,
167	                                               List<String> allowedOAuthFlows,
168	                                               List<String> allowedOAuthScopes) {
169	        describeUserPool(userPoolId);
170	        String clientId = UUID.randomUUID().toString().replace("-", "").substring(0, 26);
171	        UserPoolClient client = new UserPoolClient();
172	        client.setClientId(clientId);
173	        client.setUserPoolId(userPoolId);
174	        client.setClientName(clientName);
175	        client.setGenerateSecret(generateSecret);
176	        client.setAllowedOAuthFlowsUserPoolClient(allowedOAuthFlowsUserPoolClient);
177	        client.setAllowedOAuthFlows(normalizeStringList(allowedOAuthFlows));
178	        client.setAllowedOAuthScopes(normalizeStringList(allowedOAuthScopes));
179	        if (generateSecret) {
180	            client.setClientSecret(generateSecretValue());
181	        }
182	        clientStore.put(clientId, client);
183	        LOG.infov("Created User Pool Client: {0} for pool {1}", clientId, userPoolId);
184	        return client;
185	    }
186	
187	    public UserPoolClient describeUserPoolClient(String userPoolId, String clientId) {
188	        UserPoolClient client = clientStore.get(clientId)
189	                .orElseThrow(() -> new AwsException("ResourceNotFoundException", "User pool client not found", 404));
190	        if (!client.getUserPoolId().equals(userPoolId)) {
191	            throw new AwsException("ResourceNotFoundException", "User pool client not found", 404);
