358	    private boolean matchesUserFilter(CognitoUser user, String filter) {
359	        String originalFilter = filter;
360	        filter = filter.trim();
361	        boolean startsWithOp = filter.contains("^=");
362	        int opIdx = startsWithOp ? filter.indexOf("^=") : filter.indexOf('=');
363	        if (opIdx < 0) {
364	            throw new AwsException("InvalidParameterException", "Invalid filter expression: " + filter, 400);
365	        }
366	        String attrName = filter.substring(0, opIdx).trim();
367	        String rawValue = filter.substring(opIdx + (startsWithOp ? 2 : 1)).trim();
368	        if (rawValue.length() >= 2 && rawValue.startsWith("\"") && rawValue.endsWith("\"")) {
369	            rawValue = rawValue.substring(1, rawValue.length() - 1);
370	        }
371	        String attrValue = getUserAttribute(user, attrName);
372	        boolean matches = false;
373	        if (attrValue != null) {
374	            matches = startsWithOp ? attrValue.startsWith(rawValue) : attrValue.equals(rawValue);
375	        }
376	        LOG.infov("Matching user {0} against filter [{1}]: attrName=[{2}], rawValue=[{3}], attrValue=[{4}], matches={5}",
377	                user.getUsername(), originalFilter, attrName, rawValue, attrValue, matches);
378	        return matches;
379	    }
380	
381	    private String getUserAttribute(CognitoUser user, String attrName) {
382	        return switch (attrName) {
383	            case "username" -> user.getUsername();
384	            case "cognito:user_status", "status" -> user.getUserStatus();
385	            default -> user.getAttributes().get(attrName);
386	        };
387	    }
