521	    public Map<String, Object> initiateAuth(String clientId, String authFlow, Map<String, String> authParameters) {
522	        UserPoolClient client = clientStore.get(clientId)
523	                .orElseThrow(() -> new AwsException("ResourceNotFoundException", "Client not found", 404));
524	        UserPool pool = describeUserPool(client.getUserPoolId());
525	
526	        return switch (authFlow) {
527	            case "USER_PASSWORD_AUTH" -> authenticateWithPassword(pool, authParameters, clientId);
528	            case "REFRESH_TOKEN_AUTH", "REFRESH_TOKEN" -> handleRefreshToken(pool, authParameters, clientId);
529	            case "USER_SRP_AUTH" -> handleUserSrpAuth(pool, client, authParameters);
530	            default -> {
531	                // For other flows, if user exists return tokens
532	                String username = authParameters.get("USERNAME");
533	                if (username == null) {
534	                    throw new AwsException("InvalidParameterException", "USERNAME is required", 400);
535	                }
536	                CognitoUser user = adminGetUser(pool.getId(), username);
537	                Map<String, Object> result = new HashMap<>();
538	                result.put("AuthenticationResult", generateAuthResult(user, pool, clientId));
539	                yield result;
540	            }
541	        };
542	    }
543	
544	    public Map<String, Object> adminInitiateAuth(String userPoolId, String clientId, String authFlow,
545	                                                  Map<String, String> authParameters) {
546	        UserPoolClient client = describeUserPoolClient(userPoolId, clientId);
547	        UserPool pool = describeUserPool(userPoolId);
548	
549	        return switch (authFlow) {
550	            case "ADMIN_USER_PASSWORD_AUTH", "USER_PASSWORD_AUTH" ->
551	                    authenticateWithPassword(pool, authParameters, clientId);
552	            case "REFRESH_TOKEN_AUTH", "REFRESH_TOKEN" -> handleRefreshToken(pool, authParameters, clientId);
553	            case "ADMIN_USER_SRP_AUTH" -> handleUserSrpAuth(pool, client, authParameters);
554	            default -> {
555	                String username = authParameters.get("USERNAME");
556	                CognitoUser user = adminGetUser(userPoolId, username);
557	                Map<String, Object> result = new HashMap<>();
558	                result.put("AuthenticationResult", generateAuthResult(user, pool, clientId));
559	                yield result;
560	            }
561	        };
562	    }
563	
564	    private Map<String, Object> handleUserSrpAuth(UserPool pool, UserPoolClient client, Map<String, String> authParameters) {
565	        String username = authParameters.get("USERNAME");
566	        String aHex = authParameters.get("SRP_A");
567	
568	        if (username == null || aHex == null) {
569	            throw new AwsException("InvalidParameterException", "USERNAME and SRP_A are required", 400);
570	        }
571	
572	        CognitoUser user = adminGetUser(pool.getId(), username);
573	        if (user.getSrpVerifier() == null) {
574	            throw new AwsException("NotAuthorizedException", "User does not support SRP auth", 400);
575	        }
576	
577	        String[] serverB = CognitoSrpHelper.generateServerB(user.getSrpVerifier());
578	        String bHex = serverB[0];
579	        String bPublicHex = serverB[1];
580	
581	        String sessionToken = buildSessionToken(pool.getId(), user.getUsername(), client.getClientId());
582	
583	        byte[] secretBlock = new byte[16];
584	        new java.security.SecureRandom().nextBytes(secretBlock);
585	        String secretBlockBase64 = Base64.getEncoder().encodeToString(secretBlock);
586	
587	        srpSessions.put(sessionToken, new SrpSession(
588	                pool.getId(),
589	                user.getUsername(),
590	                client.getClientId(),
591	                aHex,
592	                bHex,
593	                bPublicHex,
594	                secretBlockBase64
595	        ));
596	
597	        Map<String, Object> result = new HashMap<>();
598	        result.put("ChallengeName", "PASSWORD_VERIFIER");
599	        result.put("Session", sessionToken);
600	        result.put("ChallengeParameters", Map.of(
601	                "SALT", user.getSrpSalt(),
602	                "SRP_B", bPublicHex,
603	                "SECRET_BLOCK", secretBlockBase64,
604	                "USER_ID_FOR_SRP", user.getUsername()
605	        ));
606	        return result;
607	    }
608	
609	    private Map<String, Object> handlePasswordVerifierChallenge(UserPool pool, UserPoolClient client,
610	                                                                 String session, Map<String, String> responses) {
611	        SrpSession srp = srpSessions.get(session);
612	        if (srp == null) {
613	            throw new AwsException("NotAuthorizedException", "Session not found", 400);
614	        }
615	
616	        String username = responses.get("USERNAME");
617	        String claimSignature = responses.get("PASSWORD_CLAIM_SIGNATURE");
618	        String timestamp = responses.get("TIMESTAMP");
619	
620	        if (username == null || claimSignature == null || timestamp == null) {
621	            throw new AwsException("InvalidParameterException", "USERNAME, PASSWORD_CLAIM_SIGNATURE and TIMESTAMP are required", 400);
622	        }
623	
624	        CognitoUser user = adminGetUser(pool.getId(), username);
625	        if (user.getSrpVerifier() == null) {
626	            throw new AwsException("NotAuthorizedException", "User does not support SRP auth", 400);
627	        }
628	
629	        byte[] sessionKey = CognitoSrpHelper.computeSessionKey(srp.aHex(), srp.bHex(), srp.bPublicHex(), user.getSrpVerifier());
630	        byte[] secretBlock = Base64.getDecoder().decode(srp.secretBlockBase64());
631	
632	        boolean valid = CognitoSrpHelper.verifySignature(sessionKey, pool.getId(), user.getUsername(), secretBlock, timestamp, claimSignature);
633	
634	        if (!valid) {
635	            throw new AwsException("NotAuthorizedException", "Incorrect username or password", 400);
636	        }
637	
638	        // Session consumed
639	        srpSessions.remove(session);
640	
641	        if (user.isTemporaryPassword() || "FORCE_CHANGE_PASSWORD".equals(user.getUserStatus())) {
642	            String newSession = buildSessionToken(pool.getId(), username, client.getClientId());
643	            Map<String, Object> result = new HashMap<>();
644	            result.put("ChallengeName", "NEW_PASSWORD_REQUIRED");
645	            result.put("Session", newSession);
646	            result.put("ChallengeParameters", Map.of(
647	                    "USER_ID_FOR_SRP", username,
648	                    "requiredAttributes", "[]",
649	                    "userAttributes", "{}"
650	            ));
651	            return result;
652	        }
653	
654	        Map<String, Object> result = new HashMap<>();
655	        result.put("AuthenticationResult", generateAuthResult(user, pool, client.getClientId()));
656	        return result;
657	    }
658	
659	    public Map<String, Object> respondToAuthChallenge(String clientId, String challengeName,
660	                                                       String session, Map<String, String> responses) {
661	        UserPoolClient client = clientStore.get(clientId)
662	                .orElseThrow(() -> new AwsException("ResourceNotFoundException", "Client not found", 404));
663	        UserPool pool = describeUserPool(client.getUserPoolId());
664	
665	        if ("PASSWORD_VERIFIER".equals(challengeName)) {
666	            return handlePasswordVerifierChallenge(pool, client, session, responses);
667	        }
668	
669	        if ("NEW_PASSWORD_REQUIRED".equals(challengeName)) {
670	            String username = responses.get("USERNAME");
671	            String newPassword = responses.get("NEW_PASSWORD");
672	            if (username == null || newPassword == null) {
673	                throw new AwsException("InvalidParameterException", "USERNAME and NEW_PASSWORD are required", 400);
674	            }
675	            adminSetUserPassword(pool.getId(), username, newPassword, true);
676	            CognitoUser user = adminGetUser(pool.getId(), username);
677	            Map<String, Object> result = new HashMap<>();
678	            result.put("AuthenticationResult", generateAuthResult(user, pool, clientId));
679	            return result;
680	        }
681	
682	        throw new AwsException("InvalidParameterException", "Unsupported challenge: " + challengeName, 400);
683	    }
