772	    private Map<String, Object> authenticateWithPassword(UserPool pool, Map<String, String> params, String clientId) {
773	        String username = params.get("USERNAME");
774	        String password = params.get("PASSWORD");
775	        if (username == null) {
776	            throw new AwsException("InvalidParameterException", "USERNAME is required", 400);
777	        }
778	        if (password == null) {
779	            throw new AwsException("InvalidParameterException", "PASSWORD is required", 400);
780	        }
781	
782	        CognitoUser user = adminGetUser(pool.getId(), username);
783	
784	        if (!user.isEnabled()) {
785	            throw new AwsException("UserNotConfirmedException", "User is disabled", 400);
786	        }
787	
788	        if ("UNCONFIRMED".equals(user.getUserStatus())) {
789	            throw new AwsException("UserNotConfirmedException", "User is not confirmed", 400);
790	        }
791	
792	        if (user.getPasswordHash() == null || !user.getPasswordHash().equals(hashPassword(password))) {
793	            throw new AwsException("NotAuthorizedException", "Incorrect username or password", 400);
794	        }
795	
796	        if (user.isTemporaryPassword() || "FORCE_CHANGE_PASSWORD".equals(user.getUserStatus())) {
797	            // Return a challenge instead of auth tokens
798	            String session = buildSessionToken(pool.getId(), username, clientId);
799	            Map<String, Object> result = new HashMap<>();
800	            result.put("ChallengeName", "NEW_PASSWORD_REQUIRED");
801	            result.put("Session", session);
802	            result.put("ChallengeParameters", Map.of(
803	                    "USER_ID_FOR_SRP", username,
804	                    "requiredAttributes", "[]",
805	                    "userAttributes", "{}"
806	            ));
807	            return result;
808	        }
809	
810	        Map<String, Object> result = new HashMap<>();
811	        result.put("AuthenticationResult", generateAuthResult(user, pool, clientId));
812	        return result;
