884	    private String generateSignedJwt(CognitoUser user, UserPool pool, String type, String clientId) {
885	        String headerJson = String.format(
886	                "{\"alg\":\"RS256\",\"typ\":\"JWT\",\"kid\":\"%s\"}",
887	                escapeJson(getSigningKeyId(pool)));
888	        String header = Base64.getUrlEncoder().withoutPadding()
889	                .encodeToString(headerJson.getBytes(StandardCharsets.UTF_8));
890	
891	        long now = System.currentTimeMillis() / 1000L;
892	        String email = user.getAttributes().getOrDefault("email", user.getUsername());
893	        String groupsFragment = "";
894	        if (!user.getGroupNames().isEmpty()) {
895	            String groupsJson = user.getGroupNames().stream()
896	                    .map(g -> "\"" + escapeJsonString(g) + "\"")
897	                    .collect(Collectors.joining(",", "[", "]"));
898	            groupsFragment = ",\"cognito:groups\":" + groupsJson;
899	        }
900	        String sub = user.getAttributes().getOrDefault("sub", user.getUsername());
901	        String clientIdFragment = (clientId != null && !clientId.isBlank() && "access".equals(type))
902	                ? ",\"client_id\":\"" + escapeJson(clientId) + "\""
903	                : "";
904	        String payloadJson = String.format(
905	                "{\"sub\":\"%s\",\"event_id\":\"%s\",\"token_use\":\"%s\",\"auth_time\":%d," +
906	                "\"iss\":\"%s\",\"exp\":%d,\"iat\":%d," +
907	                "\"username\":\"%s\",\"email\":\"%s\",\"cognito:username\":\"%s\"%s%s}",
908	                escapeJson(sub), UUID.randomUUID(), type, now,
909	                escapeJson(getIssuer(pool.getId())), now + 3600, now,
910	                user.getUsername(), email, user.getUsername(), clientIdFragment, groupsFragment
911	        );
912	        String payload = Base64.getUrlEncoder().withoutPadding()
913	                .encodeToString(payloadJson.getBytes(StandardCharsets.UTF_8));
914	        return signJwt(header, payload, getSigningPrivateKey(pool));
915	    }
