934	    private String generateClientAccessToken(UserPoolClient client, UserPool pool, String scope) {
935	        String headerJson = String.format(
936	                "{\"alg\":\"RS256\",\"typ\":\"JWT\",\"kid\":\"%s\"}",
937	                escapeJson(getSigningKeyId(pool)));
938	        String header = Base64.getUrlEncoder().withoutPadding()
939	                .encodeToString(headerJson.getBytes(StandardCharsets.UTF_8));
940	
941	        long now = System.currentTimeMillis() / 1000L;
942	        StringBuilder payloadJson = new StringBuilder();
943	        payloadJson.append("{")
944	                .append("\"iss\":\"").append(escapeJson(getIssuer(pool.getId()))).append("\",")
945	                .append("\"version\":2,")
946	                .append("\"sub\":\"").append(escapeJson(client.getClientId())).append("\",")
947	                .append("\"client_id\":\"").append(escapeJson(client.getClientId())).append("\",")
948	                .append("\"token_use\":\"access\",")
949	                .append("\"exp\":").append(now + 3600).append(",")
950	                .append("\"iat\":").append(now).append(",")
951	                .append("\"jti\":\"").append(UUID.randomUUID()).append("\"");
952	        if (scope != null && !scope.isBlank()) {
953	            payloadJson.append(",\"scope\":\"").append(escapeJson(scope)).append("\"");
954	        }
955	        payloadJson.append("}");
956	
957	        String payload = Base64.getUrlEncoder().withoutPadding()
958	                .encodeToString(payloadJson.toString().getBytes(StandardCharsets.UTF_8));
959	        return signJwt(header, payload, getSigningPrivateKey(pool));
960	    }
