984	    private String resolveAuthorizedScopes(UserPoolClient client, String userPoolId, String requestedScope) {
985	        List<String> allowedScopes = normalizeStringList(client.getAllowedOAuthScopes());
986	        if (allowedScopes.isEmpty()) {
987	            throw new AwsException("InvalidScopeException", "Client has no allowed OAuth scopes", 400);
988	        }
989	
990	        List<String> effectiveScopes;
991	        if (requestedScope == null || requestedScope.isBlank()) {
992	            effectiveScopes = allowedScopes;
993	        } else {
994	            effectiveScopes = Arrays.asList(normalizeRequestedScope(requestedScope).split(" "));
995	            for (String scope : effectiveScopes) {
996	                if (!allowedScopes.contains(scope)) {
997	                    throw new AwsException("InvalidScopeException", "Scope is not allowed for this client: " + scope, 400);
998	                }
999	            }
1000	        }
1001	
1002	        Set<String> validCustomScopes = new HashSet<>();
1003	        for (ResourceServer server : listResourceServers(userPoolId)) {
1004	            for (ResourceServerScope serverScope : server.getScopes()) {
1005	                validCustomScopes.add(server.getIdentifier() + "/" + serverScope.getScopeName());
1006	            }
1007	        }
1008	
1009	        for (String scope : effectiveScopes) {
1010	            if (isBuiltInScope(scope)) {
1011	                continue;
1012	            }
1013	            if (!validCustomScopes.contains(scope)) {
1014	                throw new AwsException("InvalidScopeException", "Scope is invalid: " + scope, 400);
1015	            }
1016	        }
1017	
1018	        return String.join(" ", effectiveScopes);
1019	    }
