1021	    private String normalizeRequestedScope(String scope) {
1022	        if (scope == null || scope.isBlank()) {
1023	            return null;
1024	        }
1025	
1026	        List<String> normalized = new ArrayList<>();
1027	        for (String part : scope.trim().split("\\s+")) {
1028	            if (!part.isBlank()) {
1029	                normalized.add(part);
1030	            }
1031	        }
1032	        return normalized.isEmpty() ? null : String.join(" ", normalized);
1033	    }
