1035	    private List<ResourceServerScope> normalizeScopes(List<ResourceServerScope> scopes) {
1036	        if (scopes == null || scopes.isEmpty()) {
1037	            return List.of();
1038	        }
1039	
1040	        List<ResourceServerScope> normalized = new ArrayList<>();
1041	        Set<String> scopeNames = new HashSet<>();
1042	        for (ResourceServerScope scope : scopes) {
1043	            if (scope == null || scope.getScopeName() == null || scope.getScopeName().isBlank()) {
1044	                throw new AwsException("InvalidParameterException", "ScopeName is required", 400);
1045	            }
1046	            if (!scopeNames.add(scope.getScopeName())) {
1047	                throw new AwsException("InvalidParameterException", "Duplicate scope name: " + scope.getScopeName(), 400);
1048	            }
1049	            ResourceServerScope normalizedScope = new ResourceServerScope();
1050	            normalizedScope.setScopeName(scope.getScopeName());
1051	            normalizedScope.setScopeDescription(scope.getScopeDescription());
1052	            normalized.add(normalizedScope);
1053	        }
1054	        return normalized;
1055	    }
