1057	    private List<String> normalizeStringList(List<String> values) {
1058	        if (values == null || values.isEmpty()) {
1059	            return List.of();
1060	        }
1061	
1062	        List<String> normalized = new ArrayList<>();
1063	        Set<String> seen = new LinkedHashSet<>();
1064	        for (String value : values) {
1065	            if (value == null) {
1066	                continue;
1067	            }
1068	            String trimmed = value.trim();
1069	            if (!trimmed.isEmpty() && seen.add(trimmed)) {
1070	                normalized.add(trimmed);
1071	            }
1072	        }
1073	        return normalized;
1074	    }
