1089	    private String rsaSha256(String data, PrivateKey signingKey) {
1090	        try {
1091	            Signature signature = Signature.getInstance("SHA256withRSA");
1092	            signature.initSign(signingKey);
1093	            signature.update(data.getBytes(StandardCharsets.UTF_8));
1094	            byte[] sig = signature.sign();
1095	            return Base64.getUrlEncoder().withoutPadding().encodeToString(sig);
1096	        } catch (Exception e) {
1097	            throw new RuntimeException("JWT signing failed", e);
1098	        }
1099	    }
