1131	    private boolean ensureJwtSigningKeys(UserPool pool) {
1132	        synchronized (pool) {
1133	            boolean changed = false;
1134	
1135	            if (pool.getSigningKeyId() == null || pool.getSigningKeyId().isBlank()) {
1136	                pool.setSigningKeyId(pool.getId());
1137	                changed = true;
1138	            }
1139	
1140	            if (pool.getSigningPrivateKey() == null || pool.getSigningPrivateKey().isBlank()
1141	                    || pool.getSigningPublicKey() == null || pool.getSigningPublicKey().isBlank()) {
1142	                try {
1143	                    KeyPairGenerator generator = KeyPairGenerator.getInstance("RSA");
1144	                    generator.initialize(2048);
1145	                    KeyPair keyPair = generator.generateKeyPair();
1146	
1147	                    pool.setSigningPrivateKey(
1148	                            Base64.getEncoder().encodeToString(keyPair.getPrivate().getEncoded()));
1149	                    pool.setSigningPublicKey(
1150	                            Base64.getEncoder().encodeToString(keyPair.getPublic().getEncoded()));
1151	                    changed = true;
1152	                } catch (Exception e) {
1153	                    throw new RuntimeException("Failed to generate Cognito RSA signing keypair", e);
1154	                }
1155	            }
1156	
1157	            if (changed && pool.getId() != null) {
1158	                pool.setLastModifiedDate(System.currentTimeMillis() / 1000L);
1159	            }
1160	
1161	            return changed;
1162	        }
1163	    }
