1246	    private String escapeJsonString(String s) {
1247	        StringBuilder sb = new StringBuilder();
1248	        for (char c : s.toCharArray()) {
1249	            switch (c) {
1250	                case '"' -> sb.append("\\\"");
1251	                case '\\' -> sb.append("\\\\");
1252	                case '\b' -> sb.append("\\b");
1253	                case '\f' -> sb.append("\\f");
1254	                case '\n' -> sb.append("\\n");
1255	                case '\r' -> sb.append("\\r");
1256	                case '\t' -> sb.append("\\t");
1257	                default -> {
1258	                    if (c < 0x20) {
1259	                        sb.append(String.format("\\u%04x", (int) c));
1260	                    } else {
1261	                        sb.append(c);
1262	                    }
1263	                }
1264	            }
1265	        }
